fn test_mrl_quality_degrades_gracefully() {
    let embedder = nomic_embedder();
    let query = embedder.embed("rust programming language").unwrap();
    let relevant = embedder.embed("systems programming with memory safety").unwrap();
    let irrelevant = embedder.embed("chocolate cake baking recipe").unwrap();

