### 6. Binary Quantization Tests (nomic)
```rust
#[test]
fn test_nomic_binary_quantization() {
    let embedder = nomic_embedder();
    let embedding = embedder.embed("test binary quantization").unwrap();

    let binary = binary_quantize(&embedding);

    // 768 dims / 8 bits per byte = 96 bytes
    assert_eq!(binary.len(), 96, "768 dims should quantize to 96 bytes");

    // Verify bit-packing is correct
    for (byte_idx, byte) in binary.iter().enumerate() {
        for bit_idx in 0..8 {
            let dim_idx = byte_idx * 8 + bit_idx;
            if dim_idx < embedding.len() {
                let expected_bit = if embedding[dim_idx] > 0.0 { 1 } else { 0 };
                let actual_bit = (byte >> bit_idx) & 1;
                assert_eq!(actual_bit, expected_bit,
                    "Bit mismatch at dim {}: value={}, expected_bit={}, got={}",
                    dim_idx, embedding[dim_idx], expected_bit, actual_bit);
            }
        }
    }
}

#[test]
fn test_binary_quantization_preserves_ordering() {
    let embedder = nomic_embedder();
    let query = embedder.embed("search_query: rust programming").unwrap();
    let relevant = embedder.embed("search_document: systems programming safety").unwrap();
    let irrelevant = embedder.embed("search_document: cake baking recipe").unwrap();

    let q_bin = binary_quantize(&query);
    let r_bin = binary_quantize(&relevant);
    let i_bin = binary_quantize(&irrelevant);

    let dist_relevant = hamming_distance(&q_bin, &r_bin);
    let dist_irrelevant = hamming_distance(&q_bin, &i_bin);

    tracing::info!(
        dist_relevant = dist_relevant,
        dist_irrelevant = dist_irrelevant,
        "Binary quantization ordering"
    );

    // Relevant doc should have SMALLER hamming distance
    assert!(dist_relevant < dist_irrelevant,
        "Binary ordering broken: relevant dist {} vs irrelevant {}", dist_relevant, dist_irrelevant);
}

#[test]
fn test_binary_quantization_size_reduction() {
    let embedding = vec![0.1f32; 768];  // 768 * 4 = 3072 bytes as f32
    let binary = binary_quantize(&embedding);
    assert_eq!(binary.len(), 96);  // 96 bytes = 32x compression
    tracing::info!(
        original_bytes = 768 * 4,
        quantized_bytes = binary.len(),
        compression = format!("{}x", (768 * 4) / binary.len()),
        "Binary quantization compression"
    );
}
