fn test_nomic_long_context_8192() {
    let embedder = nomic_embedder();

    // Generate text that exceeds typical 512-token models
    let long_text = "This is a test sentence about machine learning. ".repeat(200);
    // ~200 sentences * ~8 tokens = ~1600 tokens

    let result = embedder.embed(&long_text);
    assert!(result.is_ok(), "Nomic should handle long context: {}", result.unwrap_err());
    assert_eq!(result.unwrap().len(), 768);
