#[test]
fn test_nomic_uses_full_context() {
    let embedder = nomic_embedder();

    // Create text where important info is at the end (beyond 512 tokens)
    let prefix = "irrelevant filler text about random things. ".repeat(100); // ~700 tokens
    let with_suffix = format!("{} The key topic is quantum computing algorithms.", prefix);
    let without_suffix = prefix.clone();

    let e_with = embedder.embed(&with_suffix).unwrap();
    let e_without = embedder.embed(&without_suffix).unwrap();
    let e_quantum = embedder.embed("quantum computing algorithms").unwrap();

    // The version with quantum computing at the end should be more similar to the query
    let sim_with = cosine_similarity(&e_with, &e_quantum);
    let sim_without = cosine_similarity(&e_without, &e_quantum);

    tracing::info!(
        sim_with_suffix = sim_with,
        sim_without_suffix = sim_without,
        delta = sim_with - sim_without,
        "Long context information at position >512 tokens"
    );

    assert!(sim_with > sim_without,
        "Nomic should attend to text beyond 512 tokens: with={} vs without={}",
        sim_with, sim_without);
}

#[test]
fn test_minilm_truncates_long_context() {
    let embedder = minilm_embedder();

    // MiniLM has 512 token limit - text beyond should be truncated
    let short = embedder.embed("machine learning").unwrap();
    let long = embedder.embed(&"machine learning. ".repeat(200)).unwrap();

    // Both should produce valid embeddings
    assert_eq!(short.len(), 384);
    assert_eq!(long.len(), 384);

    // They should still be related (start is same)
    let sim = cosine_similarity(&short, &long);
    assert!(sim > 0.5, "Truncated text should still be related to short version");
}
