### 11. Thread Safety Tests
```rust
#[test]
fn test_concurrent_embedding() {
    let embedder = Arc::new(minilm_embedder());
    let handles: Vec<_> = (0..8).map(|i| {
        let e = embedder.clone();
        std::thread::spawn(move || {
            e.embed(&format!("thread {} text", i)).unwrap()
        })
    }).collect();

    let results: Vec<_> = handles.into_iter().map(|h| h.join().unwrap()).collect();
    assert_eq!(results.len(), 8);
    assert!(results.iter().all(|r| r.len() == embedder.dimensions()));
}

#[test]
fn test_concurrent_embedding_deterministic() {
    let embedder = Arc::new(minilm_embedder());
    let text = "determinism across threads";

    let handles: Vec<_> = (0..4).map(|_| {
        let e = embedder.clone();
        let t = text.to_string();
        std::thread::spawn(move || e.embed(&t).unwrap())
    }).collect();

    let results: Vec<_> = handles.into_iter().map(|h| h.join().unwrap()).collect();
    for i in 1..results.len() {
        assert_eq!(results[0], results[i], "Thread {} produced different embedding", i);
    }
}
